-- Somali University demo data for Moodle (MySQL/MariaDB)
-- Generated by tools/create-somali-university-demo-data.js on 2026-07-17.
--
-- ASSUMPTIONS - review before running:
--   * Table prefix: set via DB_PREFIX in the generator (currently mdlgx_).
--   * Roles 'editingteacher' and 'student' exist (Moodle defaults).
--   * Courses are placed in the site's first course category.
--   * Every demo account gets the SAME password: SUDemo2026!
--     (bcrypt hash below; change passwords after the demo).
--   * Safe to re-run: every insert skips rows that already exist.
--
-- AFTER RUNNING: purge caches (php admin/cli/purge_caches.php) so the
-- new courses and enrolments appear. Course context paths are set by
-- this script; Moodle's cron heals anything remaining.
--
-- CLEANUP (when the demo is over): see the commented block at the end.

START TRANSACTION;

-- 1) Users ------------------------------------------------------------
DROP TEMPORARY TABLE IF EXISTS tmp_su_users;
CREATE TEMPORARY TABLE tmp_su_users (
  username VARCHAR(100) PRIMARY KEY,
  firstname VARCHAR(100),
  lastname VARCHAR(100),
  email VARCHAR(100)
);




   city, country, lang, timezone, timecreated, timemodified)
SELECT 'manual', 1,
       (SELECT CAST(value AS UNSIGNED) FROM mdlgx_config WHERE name = 'mnet_localhost_id'),
       t.username, '$2y$10$wF5wvYEyod5IcmiB0H1EOuTLCpEVONoa0OYmiIPbfRIns3DCzEvbi', t.firstname, t.lastname, t.email,
       'Mogadishu', 'SO', 'en', 'Africa/Mogadishu', UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
FROM tmp_su_users t
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_user u WHERE u.username = t.username AND u.deleted = 0);

-- 2) Courses ----------------------------------------------------------

SELECT (SELECT MIN(id) FROM mdlgx_course_categories), 0, 'Academic English I', 'su-eng101', 'SU-ENG101',
       'Academic English I - Somali University Year 1 course. Schedule: Mon/Wed 10:00 AM.', 1, 'topics', UNIX_TIMESTAMP(), 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_course WHERE shortname = 'su-eng101');

SELECT (SELECT MIN(id) FROM mdlgx_course_categories), 0, 'University Mathematics I', 'su-math101', 'SU-MATH101',
       'University Mathematics I - Somali University Year 1 course. Schedule: Tue/Thu 8:00 AM.', 1, 'topics', UNIX_TIMESTAMP(), 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_course WHERE shortname = 'su-math101');

SELECT (SELECT MIN(id) FROM mdlgx_course_categories), 0, 'Introduction to Computing', 'su-ict101', 'SU-ICT101',
       'Introduction to Computing - Somali University Year 1 course. Schedule: Sat/Sun 4:00 PM.', 1, 'topics', UNIX_TIMESTAMP(), 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_course WHERE shortname = 'su-ict101');

SELECT (SELECT MIN(id) FROM mdlgx_course_categories), 0, 'Arabic Language I', 'su-arb101', 'SU-ARB101',
       'Arabic Language I - Somali University Year 1 course. Schedule: Mon/Thu 2:00 PM.', 1, 'topics', UNIX_TIMESTAMP(), 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_course WHERE shortname = 'su-arb101');

SELECT (SELECT MIN(id) FROM mdlgx_course_categories), 0, 'Principles of Economics I', 'su-econ101', 'SU-ECON101',
       'Principles of Economics I - Somali University Year 1 course. Schedule: Tue/Sat 6:00 PM.', 1, 'topics', UNIX_TIMESTAMP(), 1, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_course WHERE shortname = 'su-econ101');

-- 3) Course contexts (created with correct path/depth) ----------------
SELECT 50, c.id, 0, NULL
FROM mdlgx_course c
WHERE c.shortname IN ('su-eng101', 'su-math101', 'su-ict101', 'su-arb101', 'su-econ101')
  AND NOT EXISTS (SELECT 1 FROM mdlgx_context x WHERE x.contextlevel = 50 AND x.instanceid = c.id);

UPDATE mdlgx_context ctx
JOIN mdlgx_course c ON c.id = ctx.instanceid AND ctx.contextlevel = 50
JOIN mdlgx_context catctx ON catctx.contextlevel = 40 AND catctx.instanceid = c.category
SET ctx.depth = catctx.depth + 1,
    ctx.path = CONCAT(catctx.path, '/', ctx.id)
WHERE c.shortname IN ('su-eng101', 'su-math101', 'su-ict101', 'su-arb101', 'su-econ101')
  AND (ctx.path IS NULL OR ctx.depth = 0);

-- 4) Manual enrolment method on each course ---------------------------
SELECT 'manual', 0, c.id, 0,
       (SELECT id FROM mdlgx_role WHERE shortname = 'student'),
       UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
FROM mdlgx_course c
WHERE c.shortname IN ('su-eng101', 'su-math101', 'su-ict101', 'su-arb101', 'su-econ101')
  AND NOT EXISTS (SELECT 1 FROM mdlgx_enrol e WHERE e.courseid = c.id AND e.enrol = 'manual');

-- 5) Enrolments and role assignments ----------------------------------
DROP TEMPORARY TABLE IF EXISTS tmp_su_enrol;
CREATE TEMPORARY TABLE tmp_su_enrol (
  username VARCHAR(100),
  shortname VARCHAR(255),
  role VARCHAR(30),
  KEY idx_u (username), KEY idx_s (shortname)
);







SELECT 0, e.id, u.id, UNIX_TIMESTAMP(), 0, 0, UNIX_TIMESTAMP(), UNIX_TIMESTAMP()
FROM tmp_su_enrol t
JOIN mdlgx_user u ON u.username = t.username AND u.deleted = 0
JOIN mdlgx_course c ON c.shortname = t.shortname
JOIN mdlgx_enrol e ON e.courseid = c.id AND e.enrol = 'manual'
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_user_enrolments ue WHERE ue.enrolid = e.id AND ue.userid = u.id);

SELECT r.id, ctx.id, u.id, '', 0, UNIX_TIMESTAMP(), 0
FROM tmp_su_enrol t
JOIN mdlgx_user u ON u.username = t.username AND u.deleted = 0
JOIN mdlgx_course c ON c.shortname = t.shortname
JOIN mdlgx_context ctx ON ctx.contextlevel = 50 AND ctx.instanceid = c.id
JOIN mdlgx_role r ON r.shortname = t.role
WHERE NOT EXISTS (SELECT 1 FROM mdlgx_role_assignments ra WHERE ra.roleid = r.id AND ra.contextid = ctx.id AND ra.userid = u.id);

-- 6) Account numbers (5-digit user.idnumber) --------------------------
-- The workspace UI shows "Account No. pending repair" for users whose
-- idnumber is not a 5-digit code (accesslib.php pqh_account_no_value).
-- Assign sequential demo numbers 70001+ to the su-* accounts.
SET @acct := 70000;
UPDATE mdlgx_user
SET idnumber = (@acct := @acct + 1)
WHERE username LIKE 'su-%' AND deleted = 0
  AND (idnumber IS NULL OR idnumber = '' OR idnumber NOT REGEXP '^[0-9]{5}$')
ORDER BY id;

DROP TEMPORARY TABLE IF EXISTS tmp_su_users;
DROP TEMPORARY TABLE IF EXISTS tmp_su_enrol;

COMMIT;

